-- Seed the curated projects. Run once in the Supabase SQL editor AFTER
-- supabase-schema.sql. Safe to re-run: on conflict it refreshes the curated
-- content (incl. the why/features showcase) but leaves live_url, loom_id and
-- source, which you manage in /admin. Generated by scripts/gen-seed.ts.

insert into projects (id, title, summary, why, features, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('tq_chatbot', 'tq chatbot', 'a multi-tenant funnel chatbot that talks to a visitor, scores how serious they are in real time, and pushes the hot ones straight to a booked call. build it once, reconfigure it per client.', 'i wanted one closer i could reuse for any client instead of rebuilding it each time, so a whole client setup, the personality, the qualifying logic, the scoring weights, is a single database row. and i built it as a closer, not a support bot. the only test that matters is whether it books a high-intent visitor faster than a contact form would.', '[{"label":"scores intent in real time","detail":"on every message the model pulls five buying signals and weights them into one score. that score, not a keyword, decides what the bot does next."},{"label":"knows when to stop selling","detail":"a state machine walks greeting to qualifying to closing. once a lead is hot it stops asking and drops the calendly card, so it never talks a booked call back out of the room."},{"label":"three lead paths","detail":"hot leads book a call and notify the team, warm leads get their email captured for follow-up, and cold leads get a polite exit and are stored quietly. no lead is spammed or lost."},{"label":"one row per client","detail":"the same engine runs every client bot. swapping a client means swapping one supabase row, so nothing is rebuilt and nothing is shared between them."},{"label":"runs for zero dollars until it earns","detail":"with no api keys it runs on local storage, a mock closer, and log-only alerts, so i can build and demo it for free. each part promotes to production one key at a time."},{"label":"no crm lock-in","detail":"hot-lead events fire to a single per-client n8n webhook, and n8n fans them out to email, slack, or wherever the client already works."}]'::jsonb, array['runs for zero dollars with no api keys', 'promotes to production one key at a time']::text[], 'ai', 'featured', array['react', 'fastapi', 'supabase', 'groq', 'n8n', 'cloudflare']::text[], array['widget', 'fastapi', 'supabase', 'groq', 'n8n', 'booked call']::text[], 'https://github.com/adxoxo/chatbot-closer', '2026', 10, 13, 15, 'manual')
  on conflict (id) do update set title = excluded.title, summary = excluded.summary, why = excluded.why, features = excluded.features, outcome = excluded.outcome, cluster = excluded.cluster, status = excluded.status, stack = excluded.stack, schematic = excluded.schematic, github_url = excluded.github_url, year = excluded.year, sort_order = excluded.sort_order, map_x = excluded.map_x, map_y = excluded.map_y;
insert into projects (id, title, summary, why, features, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('grimoire', 'grimoire', 'a local knowledge base that every coding agent reaches through a single mcp gateway. it ingests documents, remembers past sessions, and hands back only what is relevant, project by project. everything runs offline on my own machine.', 'i wanted a second brain. one store my coding agents and i both read from, so nothing gets repeated. it also runs my day, with a to-do list on the eisenhower matrix and a timetable that regenerates as the day shifts, since i never keep a fixed schedule.', '[{"label":"runs on my own machine","detail":"chunking and embedding happen locally on my own gpu. nothing about my notes leaves the device."},{"label":"500-token chunks, small overlap","detail":"text is split into ~500-token chunks with a small carry-over overlap, so an idea that straddles a boundary is never lost."},{"label":"768-dimension local embeddings","detail":"a local nomic-embed model turns each chunk into a 768-dimension vector, stored in sqlite-vec."},{"label":"graph-tree, one to two hop retrieval","detail":"a query starts at the project node and walks one to two hops out through the graph, so it pulls only related context, never the whole base."},{"label":"narrow vector search","detail":"the vector search runs only over that graph-narrowed set of candidates, not across everything."},{"label":"time-weighted scoring","detail":"results rank by similarity times a recency decay, so what i touched recently surfaces first."}]'::jsonb, array['retrieval, memory and compaction all verified', 'embeddings running on a local gpu']::text[], 'ai', 'featured', array['python', 'sqlite-vec', 'fastmcp', 'ollama', 'opentelemetry']::text[], array['agents', 'mcp gateway', 'sqlite-vec']::text[], 'https://github.com/adxoxo/grimoire', '2026', 20, 31, 44, 'manual')
  on conflict (id) do update set title = excluded.title, summary = excluded.summary, why = excluded.why, features = excluded.features, outcome = excluded.outcome, cluster = excluded.cluster, status = excluded.status, stack = excluded.stack, schematic = excluded.schematic, github_url = excluded.github_url, year = excluded.year, sort_order = excluded.sort_order, map_x = excluded.map_x, map_y = excluded.map_y;
insert into projects (id, title, summary, why, features, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('vault', 'aquryu vault', 'a personal money operating system. a mobile-first pwa for logging income, expenses, and transfers across multiple wallets, with one glanceable picture of total money. it earns in both php and usd and converts usd at the official bsp rate captured at log time.', 'i wanted logging money to be friction-free. every added tap is a logged expense that never happens, so the whole app is built around three taps or fewer, or by voice.', '[{"label":"three taps or fewer","detail":"the app opens on the quick-log screen with a glanceable total balance, so recording money is the first thing you do, not something buried in menus."},{"label":"voice logging in taglish","detail":"speak an entry and groq whisper transcribes it, then llama parses it into a structured transaction and maps spoken wallet names to your real accounts, with a one-line confirm before it commits."},{"label":"multi-currency at the bsp rate","detail":"usd income converts to php at the official bsp rate for the day it landed, stored per transaction so history is never retroactively recomputed."},{"label":"balances that never drift","detail":"every wallet balance is derived from a starting balance plus every transaction, stored as integer centavos so rounding never creeps in."},{"label":"offline-first pwa","detail":"installable on a mid-range phone and tuned for high-glare outdoor use, it keeps logging offline then reconciles when the connection returns."}]'::jsonb, array['secrets never reach the browser; every table locked by row-level security', 'runs on cloudflare pages with supabase, no server to manage']::text[], 'fullstack', 'featured', array['sveltekit', 'supabase', 'cloudflare', 'groq', 'typescript']::text[], array['pwa', 'cloudflare functions', 'supabase', 'groq']::text[], 'https://github.com/adxoxo/aquryu-vault', '2026', 30, 80, 42, 'manual')
  on conflict (id) do update set title = excluded.title, summary = excluded.summary, why = excluded.why, features = excluded.features, outcome = excluded.outcome, cluster = excluded.cluster, status = excluded.status, stack = excluded.stack, schematic = excluded.schematic, github_url = excluded.github_url, year = excluded.year, sort_order = excluded.sort_order, map_x = excluded.map_x, map_y = excluded.map_y;
insert into projects (id, title, summary, why, features, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('goatedtracking', 'goatedtracking', 'a local-first monitoring system for a small goat farm here in the philippines. every goat wears a qr ear tag. scan it on the farm wifi and its whole profile opens: health records, vaccinations, pen, lineage. the internet is optional, not required.', 'the farm is in a part of the philippines where the internet drops and the power cuts, so i built it local-first: one server on the farm wifi with no cloud in the path. and it has two doors on one system, because a worker out in the pens should just scan a tag and see the goat, while the office needs a full dashboard behind a login.', '[{"label":"qr ear tag to profile","detail":"registering a goat generates a qr printed on its ear tag. scanning it opens that goat profile in any phone browser on the farm wifi, with no app to install and no login for the worker."},{"label":"runs with the internet off","detail":"one on-premise server holds everything, reachable at goatfarm.local over the farm wifi. the cloud is never in the path, because rural power and internet are not something to depend on."},{"label":"two doors, one system","detail":"admins log in for the full dashboard to register goats, transfer pens, print tags and read alerts. field workers just scan and log a quick health note, no account needed."},{"label":"inbreeding check on every transfer","detail":"moving a goat walks its lineage and flags whether the pen already holds close relatives, then warns the admin and lets them decide. it advises, it never blocks."},{"label":"health that surfaces itself","detail":"each vaccination records its next due date, and an alerts feed lists overdue and due-soon goats, so a missed shot gets caught instead of forgotten."},{"label":"nothing is ever deleted","detail":"a goat is marked sold, deceased or quarantined, never removed, so its full history and lineage stay intact for the herd records."}]'::jsonb, array['one on-premise server, zero cloud for the core', 'works on any phone on the farm wifi']::text[], 'fullstack', 'featured', array['django', 'postgres', 'react', 'docker']::text[], array['qr tag', 'phone browser', 'django api', 'postgres']::text[], 'https://github.com/adxoxo/GoatMonitoring', '2026', 40, 66, 13, 'manual')
  on conflict (id) do update set title = excluded.title, summary = excluded.summary, why = excluded.why, features = excluded.features, outcome = excluded.outcome, cluster = excluded.cluster, status = excluded.status, stack = excluded.stack, schematic = excluded.schematic, github_url = excluded.github_url, year = excluded.year, sort_order = excluded.sort_order, map_x = excluded.map_x, map_y = excluded.map_y;
insert into projects (id, title, summary, why, features, outcome, cluster, status, stack, schematic, github_url, year, sort_order, map_x, map_y, source) values ('grece', 'grece hydroponics', 'an automated nutrient film hydroponics setup. a raspberry pi and an arduino hold water flow, lighting, and nutrient dosing steady, while ph, ec, temperature and humidity stream to a django api you can watch and adjust from anywhere.', 'i wanted a hydroponics setup that holds the right conditions on its own and lets me watch and tune it from anywhere, instead of checking the water by hand every day. so i split it the way embedded work should: the arduino handles the real-time hardware, and a raspberry pi runs the logic, the history and the api.', '[{"label":"arduino runs the hardware, the pi runs the logic","detail":"the arduino reads the sensors and drives the pumps, lights and dosing relays in real time, then streams readings to a raspberry pi over serial. the pi holds the control logic, the database and the api."},{"label":"holds ph, ec, temp and humidity in range","detail":"ph, ec, water temperature and humidity are read continuously, and the system manages water flow, lighting and nutrient dosing to keep the nutrient film in the right band without someone standing over it."},{"label":"watch and tune it from anywhere","detail":"a django rest api exposes live readings and settings, so you can check the setup and adjust targets remotely instead of walking to the tank."},{"label":"every reading logged","detail":"sensor data is stored over time, so you can see how conditions moved across a grow and set the targets from real history instead of guesswork."},{"label":"thresholds that alert","detail":"set a safe range per variable and anything outside it is flagged, so a bad ph or ec swing is caught early instead of after the plants suffer."}]'::jsonb, array['real-time monitoring and remote control', 'every reading logged for later tuning']::text[], 'embedded', 'featured', array['raspberry pi', 'arduino', 'python', 'django', 'c++']::text[], array['sensors', 'arduino', 'raspberry pi', 'django api']::text[], 'https://github.com/adxoxo/GRECE-Hydroponics-Monitoring-', '2026', 50, 66, 66, 'manual')
